blocks.body:
{
    "level": "A1–B1",
    "intro": "W tym temacie poznasz <strong>wszystkie główne typy zaimków</strong> w języku angielskim i ich reguły użycie.",
    "rules": [
        {
            "label": "Osobiste",
            "color": "emerald",
            "text": "<strong>Zaimki osobowe</strong> – kto działa:",
            "example": "Pracuję. Ona czyta. Grają."
        },
        {
            "label": "Zaborczy",
            "color": "blue",
            "text": "<strong>Formy dzierżawcze</strong> – czyj to jest:",
            "example": "moja książka, moja, jego, jej"
        },
        {
            "label": "Odruchowy",
            "color": "amber",
            "text": "<strong>Odruchowy zaimki</strong> - działanie na siebie:",
            "example": "Zrobiłem to sam. Sama się tego nauczyła."
        }
    ]
}

{
    "title": "1. Rodzaje zaimków",
    "intro": "Istnieje kilka głównych typów zaimków w języku angielskim:",
    "items": [
        {
            "label": "Osobiste",
            "title": "Osobiste",
            "subtitle": "Ja, ty, on, ona, to, my, oni — kto robi lub otrzymuje akcja"
        },
        {
            "label": "Zaborczy",
            "title": "Zaborczy",
            "subtitle": "moje/moje, twoje/twoje, jego, jej/jej — czyj jest to"
        },
        {
            "label": "Odruchowe",
            "title": "Odwrócenie",
            "subtitle": "ja, siebie, siebie, siebie — działanie na siebie"
        },
        {
            "label": "Pokazowe",
            "title": "Wskazujące",
            "subtitle": "to, że, te, tamte — wskazują obiekty"
        },
        {
            "label": "Nieokreślony",
            "title": "Nieokreślony",
            "subtitle": "kogoś, kogokolwiek, nic — nieokreślone osoby/rzeczy"
        },
        {
            "label": "Względne",
            "title": "Względne",
            "subtitle": "kto, który, czyli – łączy części zdania"
        }
    ]
}

{
    "title": "2. Zaimki osobowe)",
    "sections": [
        {
            "label": "Zaimki podmiotowe — podmiot",
            "color": "emerald",
            "description": "Używane jako <strong>podmiot</strong> zdania (kto wykonuje czynność).",
            "examples": [
                {
                    "en": "Pracuję codziennie.",
                    "ua": "Pracuję codziennie dziennie."
                },
                {
                    "en": "Jesteś mądry.",
                    "ua": "Jesteś mądry."
                },
                {
                    "en": "On czyta książki.",
                    "ua": "On czyta książki."
                },
                {
                    "en": "Ona lubi muzykę.",
                    "ua": "Lubie muzyka."
                },
                {
                    "en": "To jest kot. kot.",
                    "ua": "Це кіт."
                },
                {
                    "en": "Jesteśmy przyjaciółmi.",
                    "ua": "Jesteśmy przyjaciółmi."
                },
                {
                    "en": "Grają w piłkę nożną.",
                    "ua": "Grają w piłkę nożną."
                }
            ]
        },
        {
            "label": "Zaimki przedmiotowe - Obiekt",
            "color": "sky",
            "description": "Używany jako <strong>dodatek</strong> (kto/co wykonuje akcję).",
            "examples": [
                {
                    "en": "Zadzwoń do mnie później.",
                    "ua": "Zadzwoń później."
                },
                {
                    "en": "Widzę cię.",
                    "ua": "Rozumiem ty."
                },
                {
                    "en": "Ona go kocha.",
                    "ua": "Ona go kocha."
                },
                {
                    "en": "Znam ją.",
                    "ua": "Znam ją."
                },
                {
                    "en": "Daj mi to.",
                    "ua": "Daj do mnie."
                },
                {
                    "en": "Zaprosili nas.",
                    "ua": "Zaprosili nas."
                },
                {
                    "en": "Lubię ich.",
                    "ua": "Lubię ich."
                }
            ]
        },
        {
            "label": "Tabela osobistych zaimki",
            "color": "purple",
            "description": "Pełna tabela zaimków podmiotu i dopełnienia:",
            "examples": [
                {
                    "en": "Ja → ja",
                    "ua": "Ja → ja"
                },
                {
                    "en": "ty → ty",
                    "ua": "ty → ty"
                },
                {
                    "en": "on → on",
                    "ua": "on → jego"
                },
                {
                    "en": "ona → ona",
                    "ua": "ona → ona"
                },
                {
                    "en": "to → to[[CODX_SEG_5]]]to → jego/jej",
                    "ua": "воно → його/її"
                },
                {
                    "en": "my → nas",
                    "ua": "my → nas"
                },
                {
                    "en": "oni → oni",
                    "ua": "oni → ich"
                }
            ],
            "note": "📌 Podmiot = podmiot (kto działa), Przedmiot = dodatek (kto/co)."
        }
    ]
}

{
    "title": "3. Formy dzierżawcze (Formy dzierżawcze) nowe.",
    "sections": [
        {
            "label": "Possessive Adjectives — Присвійні прикметники",
            "color": "blue",
            "description": "Стоять <strong>перед іменником</strong> і показують приналежність.",
            "examples": [
                {
                    "en": "This is my book.",
                    "ua": "Це моя книга."
                },
                {
                    "en": "Your car is new.",
                    "ua": "Twój samochód jest nowy."
                },
                {
                    "en": "Ma na imię John.",
                    "ua": "Ma na imię John."
                },
                {
                    "en": "Jej siostra jest lekarz.",
                    "ua": "Jej siostra jest lekarzem."
                },
                {
                    "en": "Ma kolor niebieski.",
                    "ua": "Jego kolor jest niebieski."
                },
                {
                    "en": "Nasz dom jest duży.",
                    "ua": "Nasz dom jest duży."
                },
                {
                    "en": "Ich pies jest uroczy.",
                    "ua": "Są urocze. przez rzeczownik!"
                }
            ],
            "note": "Завжди перед іменником!"
        },
        {
            "label": "Zaimki dzierżawcze – zaimki dzierżawcze",
            "color": "sky",
            "description": "<strong>Zamień</strong> rzeczownik (wstaw zamiast niego).",
            "examples": [
                {
                    "en": "Ta książka jest moja.",
                    "ua": "Ta książka jest mój."
                },
                {
                    "en": "Samochód jest twój.",
                    "ua": "Samochód jest twój."
                },
                {
                    "en": "Ten długopis jest jego.",
                    "ua": "Torba jest jej."
                },
                {
                    "en": "The bag is hers.",
                    "ua": "Dom jest nasz."
                },
                {
                    "en": "The house is ours.",
                    "ua": "Nasz dom."
                },
                {
                    "en": "Those keys are theirs.",
                    "ua": "Ті ключі їхні."
                }
            ],
            "note": "Стоять самостійно, без іменника!"
        },
        {
            "label": "Важливо!",
            "color": "amber",
            "description": "Не плутай <strong>its</strong> (присвійне) та <strong>it's</strong> (скорочення).",
            "examples": [
                {
                    "en": "Jego kolor to czerwony. (zaborczy)",
                    "ua": "Jego kolor to czerwony."
                },
                {
                    "en": "To kot. (jest)",
                    "ua": "To jest kot."
                }
            ],
            "note": "📌 Jego = zaborczy, To = skrócenie To jest."
        }
    ]
}

{
    "title": "4. Zaimki zwrotne",
    "sections": [
        {
            "label": "Formy zaimków zwrotnych",
            "color": "purple",
            "description": "Zakończone na <strong>-self</strong> (liczba pojedyncza) lub <strong>-self</strong> (liczba mnoga).",
            "examples": [
                {
                    "en": "Ja → ja",
                    "ua": "Ja → ja (self)"
                },
                {
                    "en": "ty → siebie / siebie",
                    "ua": "ty → siebie"
                },
                {
                    "en": "on → siebie",
                    "ua": "on → siebie (siebie)"
                },
                {
                    "en": "ona → siebie",
                    "ua": "ona → siebie (ona)"
                },
                {
                    "en": "to → samo",
                    "ua": "to → samo"
                },
                {
                    "en": "my → siebie",
                    "ua": "my → siebie"
                },
                {
                    "en": "oni → siebie",
                    "ua": "oni → siebie (sami)"
                }
            ]
        },
        {
            "label": "Kiedy używać",
            "color": "emerald",
            "description": "Kiedy <strong>podmiot i dopełnienie</strong> to ta sama osoba.",
            "examples": [
                {
                    "en": "Nauczyłem się angielskiego.",
                    "ua": "Nauczyłem się angielskiego."
                },
                {
                    "en": "Ona cięła się.",
                    "ua": "Pocięła się (pocięła się)."
                },
                {
                    "en": "Dobrze się bawiliśmy.",
                    "ua": "Dobrze się bawiliśmy (rozbawiliśmy się)."
                },
                {
                    "en": "Sami to zrobili.",
                    "ua": "Zrobili to. sam przyjechał. Zaimki wskazujące"
                }
            ]
        },
        {
            "label": "Emphatic use — Підсилення",
            "color": "amber",
            "description": "Для <strong>підсилення</strong>: акцент на тому, хто саме виконав дію.",
            "examples": [
                {
                    "en": "I did it myself.",
                    "ua": "Я зробив це сам (сам, без допомоги)."
                },
                {
                    "en": "The boss himself came.",
                    "ua": "Сам бос прийшов."
                },
                {
                    "en": "She fixed the car herself.",
                    "ua": "Вона сама полагодила машину."
                }
            ],
            "note": "📌 By myself/yourself = самостійно, без допомоги."
        }
    ]
}

{
    "title": "5. Вказівні займенники (Demonstrative Pronouns)",
    "sections": [
        {
            "label": "To / Tamto – liczba pojedyncza",
            "color": "blue",
            "description": "<strong>To</strong> jest blisko, <strong>To</strong> jest daleko.",
            "examples": [
                {
                    "en": "To jest mój telefon.",
                    "ua": "To jest mój telefon. (blisko)"
                },
                {
                    "en": "To jest twój samochód.",
                    "ua": "To jest twój samochód. (daleko)"
                },
                {
                    "en": "Lubię to.",
                    "ua": "Podoba mi się to."
                },
                {
                    "en": "Co to jest?",
                    "ua": "Co to jest?"
                }
            ]
        },
        {
            "label": "Te/tamte - Liczba mnoga",
            "color": "sky",
            "description": "<strong>Te</strong> - blisko, <strong>Te</strong> są daleko.",
            "examples": [
                {
                    "en": "To są moje książki.",
                    "ua": "To są moje książki. (blisko)"
                },
                {
                    "en": "To są Twoje klucze.",
                    "ua": "To są Twoje klucze. (daleko)"
                },
                {
                    "en": "Chcę te.",
                    "ua": "Chcę te."
                },
                {
                    "en": "Te są drogie.",
                    "ua": "Te są drogie."
                }
            ],
            "note": "📌 To/Tamto = liczba pojedyncza, Te/Twoje = liczba mnoga."
        }
    ]
}

{
    "title": "6. Inne typy zaimków (przegląd)",
    "sections": [
        {
            "label": "Indefinite Pronouns — Неозначені",
            "color": "purple",
            "description": "Вказують на невизначених осіб або речі.",
            "examples": [
                {
                    "en": "Ktoś dzwoni.",
                    "ua": "Ktoś dzwoni."
                },
                {
                    "en": "Każdy może to zrobić.",
                    "ua": "Każdy może to zrobić."
                },
                {
                    "en": "Nie ma rzeczy niemożliwych.",
                    "ua": " niemożliwe."
                },
                {
                    "en": "Wszyscy to wiedzą.",
                    "ua": "Wszyscy to wiedzą."
                }
            ]
        },
        {
            "label": "Zaimki względne — względne",
            "color": "emerald",
            "description": "Połącz części zdania złożonego.[[[CODX_10]]]Mężczyzna, który zadzwonił, jest moim szef.",
            "examples": [
                {
                    "en": "The man who called is my boss.",
                    "ua": " — mój szef."
                },
                {
                    "en": "Książka, którą przeczytałem, była świetna.",
                    "ua": "Książka, którą przeczytałem, była świetna."
                },
                {
                    "en": "Czerwony samochód jest mój.",
                    "ua": "Czerwony samochód jest mój moje."
                }
            ]
        },
        {
            "label": "Zaimki wzajemne — Wzajemne",
            "color": "amber",
            "description": "Wskazują wzajemne działanie.",
            "examples": [
                {
                    "en": "Oni się kochają.",
                    "ua": "Kochają się nawzajem."
                },
                {
                    "en": "Pomagamy sobie drugiego.",
                    "ua": "Pomagamy sobie nawzajem."
                }
            ],
            "note": "📌Jeden drugi = dla dwojga,Jeden drugi = dla wielu."
        }
    ]
}

{
    "title": "7. Tabela porównawcza zaimków głównych",
    "intro": "Główne formy zaimków:",
    "rows": [
        {
            "en": "Temat",
            "ua": "Temat",
            "note": "Ja, ty, on, ona, to, my, oni"
        },
        {
            "en": "Obiekt",
            "ua": "Dodatek",
            "note": "ja, ty, on, ona, to, my, oni"
        },
        {
            "en": "Przym. dzierżawczy.",
            "ua": "Zaborczy Przym.",
            "note": "mój, twój, jego, jej, jego, nasz, ich"
        },
        {
            "en": "Zaimek dzierżawczy.",
            "ua": "Zaimek dzierżawczy.",
            "note": "moje, twoje, jego, jej, nasze, ich"
        },
        {
            "en": "Odruchowe",
            "ua": "Odwróć",
            "note": "ja, siebie, siebie, siebie, siebie, siebie, siebie, samych siebie"
        }
    ],
    "warning": "]📌 Podmiot = podmiot, przedmiot = przywiązanie, dzierżawczy = zaborczy, refleksyjny = refleksyjny."
}

{
    "title": "8. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomieszanie zaimków podmiotu i dopełnienia.",
            "wrong": "Ja i John poszliśmy do parku.",
            "right": " ✅ <span class="font-mono">John i ja poszliśmy do parku park.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Pomieszanie tego i tego.",
            "wrong": "To kot. / Pies machał ogonem.",
            "right": " ✅ <span class="font-mono">To kot. / Pies machał ogonem.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pominięcie zaimka zwrotnego.",
            "wrong": "Uczyłem angielskiego.",
            "right": "​​​​ <span class="font-mono">Uczyłem się sam Angielski.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Użycie przymiotnika dzierżawczego bez rzeczownika.",
            "wrong": "Ta książka jest moja.",
            "right": "​​​​​​​ Krótkie informacje streszczenie"
        }
    ]
}

{
    "title": "10. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwy zaimek",
    "select_intro": "Wpisz w puste miejsca właściwy zaimek.",
    "selects": [
        {
            "label": "___ Jestem uczniem. (Ja / Ja)",
            "prompt": "Jaki jest zaimek?"
        },
        {
            "label": "Ta książka to ___. (mój / mój)",
            "prompt": "Jaki zaimek?"
        },
        {
            "label": "Ona to zrobiła ___. (ona / ona)",
            "prompt": "Jaki jest zaimek?"
        },
        {
            "label": "___ to mój telefon. (To / Te)",
            "prompt": "Jaki zaimek?"
        }
    ],
    "options": [
        "Ja",
        "ja",
        "moje",
        "moje",
        "ja ",
        "to",
        "te",
        "jej",
        "ona sama"
    ],
    "input_title": "Ćwiczenie 2. Wypełnij luki",
    "input_intro": "Wpisz poprawne zaimek.",
    "inputs": [
        {
            "before": "___ jak muzyka. (ja)",
            "after": " →"
        },
        {
            "before": "Daj to ___. (ja)",
            "after": "→"
        },
        {
            "before": "To jest ___ samochód. (my)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd z zaimkami.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Ja i Jan jesteśmy przyjaciele.",
            "example_target": "John i ja jesteśmy przyjaciółmi."
        },
        {
            "original": "1. Jest piękny dzień.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Ta książka jest moja.",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne strony z kategorii Zaimki i słowa orientacyjne",
    "items": [
        {
            "label": "Zaimki – zaimki (bieżące)",
            "current": true
        },
        {
            "label": "Zaimki osobowe i przedmiotowe – osobowe i dopełnienia",
            "current": false
        },
        {
            "label": "Formy dzierżawcze",
            "current": false
        },
        {
            "label": "Reflexive Pronouns — Зворотні займенники",
            "current": false
        }
    ]
}
